import java.sql.Timestamp;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.server.ResponseStatusException;

class RecallsControllerTests extends ControllerTestBase {
  @Autowired RecallsController controller;
  @Autowired NoteService noteService;

  @BeforeEach
  void setup() {
    currentUser.setUser(makeMe.aUser().please());
  }

  RecallsController nullUserController() {
    currentUser.setUser(null);
    return controller;
  }

  @Nested
  class Repeat {
    @Test
    void shouldNotBeAbleToSeeNoteIDontHaveAccessTo() {
      assertThrows(
          ResponseStatusException.class,
          () -> nullUserController().recalling("Asia/Shanghai", null));
    }

    @ParameterizedTest
    @CsvSource(
        useHeadersInDisplayName = true,
        delimiter = '|',
        textBlock =
            """
                next recall at (in hours) | timezone     | expected count
                #------------------------------------------------------------
                -1                        | Asia/Tokyo   | 1
                0                         | Asia/Tokyo   | 1
                4                         | Asia/Tokyo   | 0
                4                         | Europe/Paris | 1
                12                        | Europe/Paris | 0
                """)
    void shouldGetMemoryTrackersBasedOnTimezone(
        int nextRecallAtHours, String timezone, int expectedCount) {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      testabilitySettings.timeTravelTo(currentTime);
      makeMe
          .aMemoryTrackerBy(currentUser.getUser())
          .nextRecallAt(TimestampOperations.addHoursToTimestamp(currentTime, nextRecallAtHours))
          .please();
      DueMemoryTrackers dueMemoryTrackers = controller.recalling(timezone, null);
      assertThat(dueMemoryTrackers.getToRepeat(), hasSize(expectedCount));
    }

    @Test
    void shouldIncludeRecallStatusInDueMemoryTrackers() {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      testabilitySettings.timeTravelTo(currentTime);
      makeMe.aMemoryTrackerBy(currentUser.getUser()).nextRecallAt(currentTime).please();

      DueMemoryTrackers dueMemoryTrackers = controller.recalling("Asia/Shanghai", 0);

      assertEquals(1, dueMemoryTrackers.getToRepeat().size());
      assertEquals(1, dueMemoryTrackers.totalAssimilatedCount);
      // currentTime is 1989-01-01 00:00:00 UTC, which is 1989-01-01 08:00:00 in Asia/Shanghai
      // Since hour < 12, alignByHalfADay returns same day at 12:00:00 Asia/Shanghai = 04:00:00 UTC
      Timestamp expectedEndAt = TimestampOperations.addHoursToTimestamp(currentTime, 4);
      assertEquals(expectedEndAt, dueMemoryTrackers.getCurrentRecallWindowEndAt());
    }

    @ParameterizedTest
    @CsvSource({
      "0,  12", "6,  6", "11, 1", "12, 12", "18, 6",
    })
    void shouldSetCurrentRecallWindowEndAtAlignedByHalfADay(
        int currentHour, int expectedHoursToAdd) {
      Timestamp currentTime = makeMe.aTimestamp().of(1, currentHour).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);
      makeMe.aMemoryTrackerBy(currentUser.getUser()).nextRecallAt(currentTime).please();

      DueMemoryTrackers dueMemoryTrackers = controller.recalling("Asia/Shanghai", 0);

      Timestamp expectedEndAt =
          TimestampOperations.addHoursToTimestamp(currentTime, expectedHoursToAdd);
      assertEquals(expectedEndAt, dueMemoryTrackers.getCurrentRecallWindowEndAt());
      // Verify it's not affected by dueInDays
      DueMemoryTrackers dueMemoryTrackersWithDays = controller.recalling("Asia/Shanghai", 3);
      assertEquals(expectedEndAt, dueMemoryTrackersWithDays.getCurrentRecallWindowEndAt());
    }

    @Test
    void shouldExcludeMemoryTrackersForDeletedNotesFromRecallLists() {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      testabilitySettings.timeTravelTo(currentTime);
      Note activeNote = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      Note deletedNote = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      makeMe
          .aMemoryTrackerFor(activeNote)
          .by(currentUser.getUser())
          .nextRecallAt(currentTime)
          .please();
      makeMe
          .aMemoryTrackerFor(deletedNote)
          .by(currentUser.getUser())
          .nextRecallAt(currentTime)
          .please();

      noteService.destroy(
          deletedNote, NoteDeleteReferenceHandling.LEAVE_DEAD_LINKS, currentUser.getUser());

      DueMemoryTrackers dueMemoryTrackers = controller.recalling("Asia/Shanghai", 0);

      assertEquals(1, dueMemoryTrackers.getToRepeat().size());
      assertEquals(1, dueMemoryTrackers.totalAssimilatedCount);
      assertThat(dueMemoryTrackers.getToRepeat(), hasSize(1));
    }
  }

  @Nested
  class PreviouslyAnswered {
    @Test
    void shouldNotBeAbleToAccessWithoutLogin() {
      assertThrows(
          ResponseStatusException.class,
          () -> nullUserController().previouslyAnswered("Asia/Shanghai"));
    }

    @Test
    void shouldReturnEmptyListWhenNoAnsweredRecallPrompts() {
      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");
      assertThat(results, hasSize(0));
    }

    @Test
    void shouldReturnAnsweredRecallPromptsInCurrentWindow() {
      // Set current time to 10:00 AM Shanghai time (window: 0:00-12:00)
      Timestamp currentTime = makeMe.aTimestamp().of(1, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);

      Note note = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(currentUser.getUser()).please();

      // Create an answered recall prompt with answer timestamp within current window
      makeMe
          .aRecallPrompt()
          .withPredefinedQuestionForNote(note)
          .forMemoryTracker(memoryTracker)
          .answerChoiceIndex(0)
          .answerTimestamp(currentTime)
          .please();

      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");

      assertThat(results, hasSize(1));
      assertEquals(com.odde.doughnut.entities.QuestionType.MCQ, results.get(0).getQuestionType());
    }

    @Test
    void shouldNotReturnAnsweredRecallPromptsFromPreviousWindow() {
      // Answer a question in a previous window (yesterday at 10:00 AM)
      Timestamp previousWindowTime = makeMe.aTimestamp().of(0, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(previousWindowTime);

      Note note = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(currentUser.getUser()).please();

      makeMe
          .aRecallPrompt()
          .withPredefinedQuestionForNote(note)
          .forMemoryTracker(memoryTracker)
          .answerChoiceIndex(0)
          .answerTimestamp(previousWindowTime)
          .please();

      // Move to current window (next day at 10:00 AM)
      Timestamp currentTime = makeMe.aTimestamp().of(1, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);

      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");

      assertThat(results, hasSize(0));
    }

    @Test
    void shouldReturnSpellingResultsInCurrentWindow() {
      Timestamp currentTime = makeMe.aTimestamp().of(1, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);

      Note note = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(currentUser.getUser()).please();

      // Create an answered spelling recall prompt
      makeMe
          .aRecallPrompt()
          .forMemoryTracker(memoryTracker)
          .spelling()
          .answerSpelling("test answer")
          .answerTimestamp(currentTime)
          .please();

      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");

      assertThat(results, hasSize(1));
      assertEquals(
          com.odde.doughnut.entities.QuestionType.SPELLING, results.get(0).getQuestionType());
    }
  }
}

import { computed, ref } from "vue"
import { useRouter } from "vue-router"
import type { MemoryTrackerLite } from "@generated/doughnut-backend-api/types.gen"

const toRepeat = ref<MemoryTrackerLite[] | undefined>(undefined)
const currentRecallWindowEndAt = ref<string | undefined>(undefined)
const totalAssimilatedCount = ref<number | undefined>(undefined)
const isRecallPaused = ref(false)
const shouldResumeRecall = ref(false)
const treadmillMode = ref<boolean>(false)
const currentIndex = ref(0)
const diligentMode = ref<boolean>(false)

const dueRecallsRefreshNonce = ref(0)

const toRepeatCount = computed(() => {
  const length = toRepeat.value?.length ?? 0
  const index = currentIndex.value
  return Math.max(0, length - index)
})

export function useRecallData() {
  const router = useRouter()

  const setToRepeat = (trackers: MemoryTrackerLite[] | undefined) => {
    toRepeat.value = trackers
  }

  const setCurrentRecallWindowEndAt = (endAt: string | undefined) => {
    currentRecallWindowEndAt.value = endAt
  }

  const setTotalAssimilatedCount = (count: number | undefined) => {
    totalAssimilatedCount.value = count
  }

  const setIsRecallPaused = (paused: boolean) => {
    isRecallPaused.value = paused
  }

  const resumeRecall = () => {
    shouldResumeRecall.value = true
    router.push({ name: "recall" })
  }

  const clearShouldResumeRecall = () => {
    shouldResumeRecall.value = false
  }

  const setTreadmillMode = (enabled: boolean) => {
    treadmillMode.value = enabled
  }

  const setCurrentIndex = (index: number) => {
    currentIndex.value = index
  }

  const setDiligentMode = (enabled: boolean) => {
    diligentMode.value = enabled
  }

  const requestDueRecallsRefresh = () => {
    dueRecallsRefreshNonce.value += 1
  }

  return {
    toRepeatCount,
    toRepeat,
    currentRecallWindowEndAt,
    totalAssimilatedCount,
    isRecallPaused,
    shouldResumeRecall,
    treadmillMode,
    currentIndex,
    diligentMode,
    setToRepeat,
    setCurrentRecallWindowEndAt,
    setTotalAssimilatedCount,
    setIsRecallPaused,
    resumeRecall,
    clearShouldResumeRecall,
    setTreadmillMode,
    setCurrentIndex,
    setDiligentMode,
    dueRecallsRefreshNonce,
    requestDueRecallsRefresh,
  }
}

import {
  MemoryTrackerController,
  NoteController,
  RecallPromptController,
  RecallsController,
} from "@generated/doughnut-backend-api/sdk.gen"
import { useRecallData } from "@/composables/useRecallData"
import RecallPage from "@/pages/RecallPage.vue"
import type {
  MemoryTrackerLite,
  RecallPrompt,
} from "@generated/doughnut-backend-api"
import makeMe from "doughnut-test-fixtures/makeMe"
import helper, {
  mockSdkService,
  wrapSdkError,
  wrapSdkResponse,
} from "@tests/helpers"
import RenderingHelper from "@tests/helpers/RenderingHelper"
import mockBrowserTimeZone from "@tests/helpers/mockBrowserTimeZone"
import { flushPromises } from "@vue/test-utils"
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest"
import { computed, ref } from "vue"

vi.mock("@/composables/useRecallData")

vi.mock("vue-router", async (importOriginal) => {
  const actual = await importOriginal<typeof import("vue-router")>()
  const mockCurrentRoute = {
    value: {
      name: "recall",
    },
  }
  return {
    ...actual,
    useRoute: () => ({
      path: "/",
      fullPath: "/",
    }),
    useRouter: () => ({
      currentRoute: mockCurrentRoute,
    }),
  }
})

let renderer: RenderingHelper<typeof RecallPage>
let recallingSpy: ReturnType<typeof mockSdkService>
let previouslyAnsweredSpy: ReturnType<typeof mockSdkService>
let toRepeatRef: ReturnType<typeof ref<MemoryTrackerLite[] | undefined>>

// Helper to create useRecallData mock return value
const createUseRecallDataMock = (overrides?: {
  toRepeat?: MemoryTrackerLite[]
  currentRecallWindowEndAt?: string
  totalAssimilatedCount?: number
  isRecallPaused?: boolean
  shouldResumeRecall?: boolean
  treadmillMode?: boolean
  currentIndex?: number
  diligentMode?: boolean
}) => {
  toRepeatRef = ref<MemoryTrackerLite[] | undefined>(overrides?.toRepeat)
  const treadmillModeRef = ref(overrides?.treadmillMode ?? false)
  const currentIndexRef = ref(overrides?.currentIndex ?? 0)
  const diligentModeRef = ref(overrides?.diligentMode ?? false)
  const dueRecallsRefreshNonce = ref(0)
  return {
    toRepeatCount: computed(() => toRepeatRef.value?.length ?? 0),
    toRepeat: toRepeatRef,
    currentRecallWindowEndAt: ref(overrides?.currentRecallWindowEndAt),
    totalAssimilatedCount: ref(overrides?.totalAssimilatedCount ?? 0),
    isRecallPaused: ref(overrides?.isRecallPaused ?? false),
    shouldResumeRecall: ref(overrides?.shouldResumeRecall ?? false),
    treadmillMode: treadmillModeRef,
    currentIndex: currentIndexRef,
    diligentMode: diligentModeRef,
    setToRepeat: vi.fn((trackers: MemoryTrackerLite[] | undefined) => {
      toRepeatRef.value = trackers
    }),
    setCurrentRecallWindowEndAt: vi.fn(),
    setTotalAssimilatedCount: vi.fn(),
    setIsRecallPaused: vi.fn(),
    resumeRecall: vi.fn(),
    clearShouldResumeRecall: vi.fn(),
    setTreadmillMode: vi.fn((enabled: boolean) => {
      treadmillModeRef.value = enabled
    }),
    setCurrentIndex: vi.fn((index: number) => {
      currentIndexRef.value = index
    }),
    setDiligentMode: vi.fn((enabled: boolean) => {
      diligentModeRef.value = enabled
    }),
    dueRecallsRefreshNonce,
    requestDueRecallsRefresh: vi.fn(() => {
      dueRecallsRefreshNonce.value += 1
    }),
  }
}

afterEach(() => {
  document.body.innerHTML = ""
})

beforeEach(() => {
  vi.resetAllMocks()
  mockSdkService(NoteController, "showNote", makeMe.aNoteRealm.please())
  recallingSpy = mockSdkService(
    RecallsController,
    "recalling",
    makeMe.aDueMemoryTrackersList.please()
  )
  previouslyAnsweredSpy = mockSdkService(
    RecallsController,
    "previouslyAnswered",
    []
  )
  mockSdkService(
    MemoryTrackerController,
    "askAQuestion",
    makeMe.aRecallPrompt.withQuestionType("SPELLING").please()
  )
  vi.mocked(useRecallData).mockReturnValue(createUseRecallDataMock())
  renderer = helper
    .component(RecallPage)
    .withCleanStorage()
    .withProps({ eagerFetchCount: 1 })
})

describe("repeat page", () => {
  const createMemoryTrackerLite = (
    id: number,
    spelling = false
  ): MemoryTrackerLite => ({
    memoryTrackerId: id,
    spelling,
  })

  const mountPage = async () => {
    const wrapper = renderer.currentRoute({ name: "recall" }).mount()
    await flushPromises()
    return wrapper
  }

  mockBrowserTimeZone("Asia/Shanghai", beforeEach, afterEach)

  describe("loading previously answered recall prompts", () => {
    it("should call previouslyAnswered on mount", async () => {
      await mountPage()
      expect(previouslyAnsweredSpy).toHaveBeenCalledWith(
        expect.objectContaining({
          query: { timezone: "Asia/Shanghai" },
        })
      )
    })

    it("should prepend previously answered recall prompts to the list", async () => {
      const note = makeMe.aNote.please()
      const previousQuestionResult: RecallPrompt = makeMe.aRecallPrompt
        .withId(1)
        .withNote(note)
        .withPredefinedQuestion(makeMe.aPredefinedQuestion.please())
        .withAnswer({ id: 1, correct: true, choiceIndex: 0 })
        .withMemoryTrackerId(1)
        .please()
      previouslyAnsweredSpy.mockResolvedValueOnce(
        wrapSdkResponse([previousQuestionResult])
      )

      const wrapper = await mountPage()
      const globalBar = wrapper.findComponent({ name: "GlobalBar" })
      expect(globalBar.text()).toContain("1/")
    })
  })

  describe("due recalls refresh after assimilation", () => {
    it("calls recalling when dueRecallsRefreshNonce increments", async () => {
      const mockData = createUseRecallDataMock({ toRepeat: undefined })
      vi.mocked(useRecallData).mockReturnValue(mockData)
      await mountPage()
      recallingSpy.mockClear()
      mockData.dueRecallsRefreshNonce.value += 1
      await flushPromises()
      expect(recallingSpy).toHaveBeenCalledWith(
        expect.objectContaining({
          query: expect.objectContaining({
            timezone: "Asia/Shanghai",
            dueindays: 0,
          }),
        })
      )
    })
  })

  it("redirect to recall page if nothing to repeat", async () => {
    const repetition = makeMe.aDueMemoryTrackersList.please()
    vi.mocked(useRecallData).mockReturnValue(
      createUseRecallDataMock({ toRepeat: repetition.toRepeat })
    )
    await mountPage()
    // Should not call recalling on mount anymore since data comes from useRecallData
    expect(recallingSpy).not.toHaveBeenCalled()
  })

  describe('repeat page with "just review" quiz', () => {
    const firstMemoryTrackerId = 123
    const secondMemoryTrackerId = 456
    let askAQuestionSpy: ReturnType<typeof mockSdkService>

    beforeEach(() => {
      vi.useFakeTimers()
      mockSdkService(
        MemoryTrackerController,
        "showMemoryTracker",
        makeMe.aMemoryTracker.please()
      )
      askAQuestionSpy = mockSdkService(
        MemoryTrackerController,
        "askAQuestion",
        makeMe.aRecallPrompt.please()
      )
      askAQuestionSpy.mockResolvedValueOnce(wrapSdkError("API Error"))
      const trackers = [
        createMemoryTrackerLite(firstMemoryTrackerId),
        createMemoryTrackerLite(secondMemoryTrackerId),
        createMemoryTrackerLite(3),
      ]
      vi.mocked(useRecallData).mockReturnValue(
        createUseRecallDataMock({ toRepeat: trackers })
      )
    })

    it("shows the progress", async () => {
      const wrapper = await mountPage()
      const globalBar = wrapper.findComponent({ name: "GlobalBar" })
      expect(globalBar.text()).toContain("0/3")
      expect(askAQuestionSpy).toHaveBeenCalledWith(
        expect.objectContaining({
          path: { memoryTracker: firstMemoryTrackerId },
        })
      )
    })

    it("should show progress", async () => {
      const wrapper = await mountPage()
      const mockedMarkAsRepeatedCall = mockSdkService(
        MemoryTrackerController,
        "markAsRecalled",
        makeMe.aMemoryTracker.please()
      )
      const recallPrompt = makeMe.aRecallPrompt.please()
      askAQuestionSpy.mockResolvedValueOnce(wrapSdkResponse(recallPrompt))
      vi.runOnlyPendingTimers()
      await flushPromises()
      await wrapper.find("button.daisy-btn-primary").trigger("click")
      expect(mockedMarkAsRepeatedCall).toHaveBeenCalledWith({
        path: { memoryTracker: firstMemoryTrackerId },
        query: { successful: true },
      })
      await flushPromises()
      const globalBar = wrapper.findComponent({ name: "GlobalBar" })
      expect(globalBar.text()).toContain("1/3")
      expect(askAQuestionSpy).toHaveBeenCalledWith(
        expect.objectContaining({
          path: { memoryTracker: secondMemoryTrackerId },
        })
      )
    })

    it("should move current memory tracker to end when requested", async () => {
      const wrapper = await mountPage()
      type ExposedVM = { toRepeat?: MemoryTrackerLite[]; currentIndex: number }
      const vm = wrapper.vm as unknown as ExposedVM

      // Initial order should be [123, 456, 3]
      expect(vm.toRepeat?.map((t) => t.memoryTrackerId)).toEqual([123, 456, 3])

      // Click the progress bar to open the settings dialog
      await wrapper.find(".daisy-progress-bar").trigger("click")
      await wrapper.vm.$nextTick()
      await flushPromises()

      // Click the "Move to end" button in the modal dialog
      const moveToEndButton = document.body.querySelector(
        'button[title="Move to end of list"]'
      )
      expect(moveToEndButton).toBeTruthy()
      await moveToEndButton?.dispatchEvent(new Event("click"))
      await wrapper.vm.$nextTick()

      // New order should be [456, 3, 123]
      expect(vm.toRepeat?.map((t) => t.memoryTrackerId)).toEqual([456, 3, 123])
    })

    it("should not show move to end button for last item", async () => {
      const wrapper = await mountPage()
      type ExposedVM = { toRepeat?: MemoryTrackerLite[]; currentIndex: number }
      const vm = wrapper.vm as unknown as ExposedVM

      // Move to last item
      vm.currentIndex = 2
      await wrapper.vm.$nextTick()

      // Click the progress bar to open the settings dialog
      await wrapper.find(".daisy-progress-bar").trigger("click")
      await wrapper.vm.$nextTick()
      await flushPromises()

      // Button should not be visible when on last item
      const moveToEndButton = document.body.querySelector(
        'button[title="Move to end of list"]'
      )
      expect(moveToEndButton).toBeFalsy()
    })
  })

  describe('repeat page with "spelling" quiz', () => {
    const firstMemoryTrackerId = 123

    beforeEach(() => {
      vi.useFakeTimers()
      mockSdkService(
        MemoryTrackerController,
        "showMemoryTracker",
        makeMe.aMemoryTracker.please()
      )
      mockSdkService(
        MemoryTrackerController,
        "askAQuestion",
        makeMe.aRecallPrompt.please()
      )

      const trackers = [createMemoryTrackerLite(firstMemoryTrackerId, true)]
      vi.mocked(useRecallData).mockReturnValue(
        createUseRecallDataMock({ toRepeat: trackers })
      )
    })

    it("should handle spelling questions correctly", async () => {
      const note = makeMe.aNote.please()
      note.id = 42
      const answerResult: RecallPrompt = makeMe.aRecallPrompt
        .withNote(note)
        .withQuestionType("SPELLING")
        .withAnswer({ id: 1, correct: false, spellingAnswer: "test answer" })
        .withMemoryTrackerId(123)
        .please()

      const mockedAnswerSpellingCall = mockSdkService(
        RecallPromptController,
        "answerSpelling",
        answerResult
      )
      mockSdkService(MemoryTrackerController, "getThresholdExceeded", {
        thresholdExceeded: false,
      })

      const wrapper = await mountPage()
      await flushPromises()

      // Debug: print the wrapper's HTML
      await wrapper.find("input#memory_tracker-answer").setValue("test answer")
      await flushPromises()
      await wrapper.find("form").trigger("submit")
      await flushPromises()
      expect(mockedAnswerSpellingCall).toHaveBeenCalled()

      // Verify that a spelling result was created and displayed correctly
      const answeredSpellingQuestion = wrapper.findComponent({
        name: "AnsweredSpellingQuestion",
      })
      expect(answeredSpellingQuestion.exists()).toBe(true)
      const spellingAlert = answeredSpellingQuestion.find(".daisy-alert-error")
      expect(spellingAlert.exists()).toBe(true)
      expect(spellingAlert.text()).toContain(
        "Your answer `test answer` is incorrect."
      )

      // Verify note is displayed
      const noteShow = answeredSpellingQuestion.findComponent({
        name: "NoteShow",
      })
      expect(noteShow.exists()).toBe(true)
      expect(noteShow.props("noteId")).toBe(42)

      // Verify View Memory Tracker link is displayed
      const viewMemoryTrackerLink = answeredSpellingQuestion.findComponent({
        name: "ViewMemoryTrackerLink",
      })
      expect(viewMemoryTrackerLink.exists()).toBe(true)
      expect(viewMemoryTrackerLink.props("memoryTrackerId")).toBe(123)
    })
  })

  describe("treadmill mode", () => {
    const normalMemoryTrackerId = 123
    const spellingMemoryTrackerId = 456
    const anotherNormalMemoryTrackerId = 789
    let askAQuestionSpy: ReturnType<typeof mockSdkService>

    beforeEach(() => {
      vi.useFakeTimers()
      mockSdkService(
        MemoryTrackerController,
        "showMemoryTracker",
        makeMe.aMemoryTracker.please()
      )
      askAQuestionSpy = mockSdkService(
        MemoryTrackerController,
        "askAQuestion",
        makeMe.aRecallPrompt.please()
      )
      const trackers = [
        createMemoryTrackerLite(normalMemoryTrackerId, false),
        createMemoryTrackerLite(spellingMemoryTrackerId, true),
        createMemoryTrackerLite(anotherNormalMemoryTrackerId, false),
      ]
      vi.mocked(useRecallData).mockReturnValue(
        createUseRecallDataMock({ toRepeat: trackers })
      )
    })

    const mountPage = async () => {
      const wrapper = renderer.currentRoute({ name: "recall" }).mount()
      await flushPromises()
      return wrapper
    }

    const toggleTreadmillMode = async (
      wrapper: Awaited<ReturnType<typeof mountPage>>,
      enabled: boolean
    ) => {
      // Check if dialog is already open by looking for the checkbox
      let toggle = document.body.querySelector(
        'input[type="checkbox"]'
      ) as HTMLInputElement

      // If checkbox not found, click progress bar to open dialog
      if (!toggle) {
        await wrapper.find(".daisy-progress-bar").trigger("click")
        await wrapper.vm.$nextTick()
        await flushPromises()

        // Wait for dialog to render
        await vi.waitUntil(
          () => {
            toggle = document.body.querySelector(
              'input[type="checkbox"]'
            ) as HTMLInputElement
            return !!toggle
          },
          { timeout: 1000 }
        )
      }

      expect(toggle).toBeTruthy()
      if (toggle) {
        toggle.checked = enabled
        toggle.dispatchEvent(new Event("change", { bubbles: true }))
        await wrapper.vm.$nextTick()
        await flushPromises()
      }
    }

    it("should show treadmill mode toggle in settings", async () => {
      const wrapper = await mountPage()
      await wrapper.find(".daisy-progress-bar").trigger("click")
      await wrapper.vm.$nextTick()
      await flushPromises()

      // Dialog is shown as a modal
      const toggle = document.body.querySelector('input[type="checkbox"]')
      expect(toggle).toBeTruthy()
      expect(document.body.textContent).toContain("Treadmill mode")
    })

