            TimestampOperations.addHoursToTimestamp(
                memoryTracker.getNextRecallAt(), daysDelay * 24);
        memoryTracker.markAsRecalled(currentUTCTimestamp, true, null);
        assertThat(memoryTracker.getForgettingCurveIndex(), equalTo(expectedForgettingCurveIndex));
      }
    }
  }

  @Nested
  class RecallForecastCounts {
    @Test
    void shouldForecastCumulativeDueCountsUsingRecallLoadingRules() {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      Note note = makeMe.aNote().notebookOwnedBy(user).please();

      makeTrackerDueAt(note, currentTime);
      makeTrackerDueAt(note, TimestampOperations.addHoursToTimestamp(currentTime, 2 * 24));
      makeTrackerDueAt(note, TimestampOperations.addHoursToTimestamp(currentTime, 6 * 24));
      makeTrackerDueAt(note, TimestampOperations.addHoursToTimestamp(currentTime, 10 * 24));
      makeTrackerDueAt(note, TimestampOperations.addHoursToTimestamp(currentTime, 15 * 24));
      makeMe
          .aMemoryTrackerFor(note)
          .by(user)
          .nextRecallAt(currentTime)
          .removedFromTracking()
          .please();
      MemoryTracker deletedMemoryTracker = makeTrackerDueAt(note, currentTime);
      deletedMemoryTracker.setDeletedAt(currentTime);
      makeMe.aMemoryTrackerFor(note).by(anotherUser).nextRecallAt(currentTime).please();

      DueMemoryTrackers dueMemoryTrackers =
          recallService.getDueMemoryTrackers(user, currentTime, ZoneId.of("Asia/Shanghai"), 0);

      assertThat(forecastCountByWindow(dueMemoryTrackers).get(0), is(1));
      assertThat(forecastCountByWindow(dueMemoryTrackers).get(3), is(2));
      assertThat(forecastCountByWindow(dueMemoryTrackers).get(7), is(3));
      assertThat(forecastCountByWindow(dueMemoryTrackers).get(14), is(4));
    }
  }

  private MemoryTracker getOneMemoryTrackerNeedToRepeat(Timestamp timestamp) {
    return userService
        .getMemoryTrackersNeedToRepeat(user, timestamp, ZoneId.of("Asia/Shanghai"))
        .findFirst()
        .orElse(null);
  }

  private MemoryTracker makeTrackerDueAt(Note note, Timestamp nextRecallAt) {
    return makeMe.aMemoryTrackerFor(note).by(user).nextRecallAt(nextRecallAt).please();
  }

  private Map<Integer, Integer> forecastCountByWindow(DueMemoryTrackers dueMemoryTrackers) {
    return dueMemoryTrackers.getRecallForecasts().stream()
        .collect(Collectors.toMap(RecallForecast::getDueInDays, RecallForecast::getCount));
  }

  private Timestamp daysAfterBase(MemoryTracker memoryTracker, Integer recallDay) {
    return TimestampOperations.addHoursToTimestamp(
        memoryTracker.getLastRecalledAt(), recallDay * 24);
  }
